import{r as e}from"./rolldown-runtime-QTnfLwEv.js";import{n as t,t as n}from"./vendor-react-CIxEorsV.js";import{n as r}from"./vendor-router-XxCI5KMz.js";import"./useMeta-Ci6jPQUv.js";import{t as i}from"./SeoPage.module-DkyBZNHX.js";var a=e(t(),1),o=n();function s(){return(0,a.useEffect)(()=>{document.title=`Basketball Player Rating System | How to Rate Basketball Players | Veyro`;let e={"@context":`https://schema.org`,"@type":`Article`,headline:`Basketball Player Rating System: How to Rate Players After Every Game`,description:`A complete guide to rating basketball players using per-minute stats, efficiency metrics, and position-adjusted formulas.`,author:{"@type":`Organization`,name:`Veyro`},publisher:{"@type":`Organization`,name:`Veyro`,url:`https://darksalmon-lark-983637.hostingersite.com`},datePublished:`2026-06-01`,dateModified:`2026-06-01`,mainEntityOfPage:{"@type":`WebPage`,"@id":`https://darksalmon-lark-983637.hostingersite.com/basketball-rating-system`}},t=document.createElement(`script`);return t.type=`application/ld+json`,t.text=JSON.stringify(e),document.head.appendChild(t),()=>document.head.removeChild(t)},[]),(0,o.jsx)(`main`,{className:i.seoPage,children:(0,o.jsxs)(`article`,{children:[(0,o.jsxs)(`section`,{className:i.hero,children:[(0,o.jsx)(`div`,{className:i.eyebrow,children:`Basketball Analytics`}),(0,o.jsx)(`h1`,{className:i.h1,children:`How to build a basketball player rating system.`}),(0,o.jsx)(`p`,{children:`Basketball is one of the most stat-rich sports at every level. Box scores capture points, rebounds, assists, steals, blocks, turnovers, and shooting percentages in every game. But raw box score stats without adjustment reward high-volume players and punish efficient players who play fewer minutes. A good basketball rating system fixes that by scaling everything to minutes played and weighting efficiency over volume.`}),(0,o.jsxs)(`div`,{className:i.actions,children:[(0,o.jsx)(r,{className:i.button,to:`/basketball`,children:`Try Basketball Calculator`}),(0,o.jsx)(r,{className:i.button,to:`/basketball/vault`,children:`Basketball Vault`})]})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`Why per-minute stats matter more than totals.`}),(0,o.jsx)(`p`,{children:`A player who scores 18 points in 34 minutes is less efficient than a player who scores 14 points in 22 minutes. Per-minute scoring (points per 36 minutes, or points per minute) levels the comparison. The same logic applies to every counting stat: rebounds per minute, assists per minute, steals per minute. Total stats reward playing time; per-minute stats reward production.`}),(0,o.jsx)(`p`,{children:`The Veyro basketball rating formula scales all positive contributions by minutes played so that a player who comes off the bench for twelve explosive minutes is rated fairly against a starter who plays thirty-two steady minutes.`})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`The key stats for a basketball rating.`}),(0,o.jsxs)(`div`,{className:i.grid,children:[(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Points`}),(0,o.jsx)(`span`,{children:`Weighted heavily. Scoring is the most direct contribution to winning. Goals come from good decisions and execution under pressure.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Assists`}),(0,o.jsx)(`span`,{children:`Weighted significantly. Creating scoring opportunities for teammates is as valuable as scoring directly, especially for point guards.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Rebounds`}),(0,o.jsx)(`span`,{children:`Weighted moderately. Offensive rebounds are slightly more valuable than defensive rebounds because they create extra possessions.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Steals and blocks`}),(0,o.jsx)(`span`,{children:`Weighted well above their frequency. Defensive plays that create turnovers or end possessions have outsized impact on game outcome.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Turnovers`}),(0,o.jsx)(`span`,{children:`A negative. Turnovers directly give the opponent possessions. A player with high scoring but high turnovers may be hurting the team overall.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Field goal efficiency`}),(0,o.jsx)(`span`,{children:`The ratio of field goals made to attempted. A player shooting 8/12 contributes more efficiently than one shooting 8/20, even with the same points.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Plus/minus`}),(0,o.jsx)(`span`,{children:`The team's scoring margin while the player is on the floor. A useful secondary signal that captures things the box score misses.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Minutes`}),(0,o.jsx)(`span`,{children:`The denominator for all per-minute calculations. Essential input. A player who plays zero minutes has no rating.`})]})]})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`How the Veyro basketball formula works.`}),(0,o.jsx)(`p`,{children:`The formula starts at a base score of 60 â€” representing a player who shows up and plays their role without major positive or negative contributions. From there, it adds scaled per-minute contributions for points, assists, rebounds, steals, and blocks, then subtracts for turnovers, and applies a secondary adjustment for field goal efficiency and plus/minus.`}),(0,o.jsx)(`p`,{children:`A player who scores 20 points in 28 minutes with 6 assists, 5 rebounds, 2 steals, and only 2 turnovers will land near 90-95 out of 100. A player who scores 8 points in 32 minutes with 8 turnovers and a -12 plus/minus may land below 50. The formula is intentionally calibrated so that genuinely elite performances produce scores above 90, and that the 60-80 range represents the reliable contribution that most good youth and amateur players produce.`})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`Rating basketball players by position.`}),(0,o.jsxs)(`div`,{className:i.grid,children:[(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Point guard`}),(0,o.jsx)(`span`,{children:`Weight assists heavily. A PG who scores 12 but dishes 9 assists may rate higher than one who scores 18 with 3 assists. Turnovers are especially costly for ball handlers.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Shooting guard`}),(0,o.jsx)(`span`,{children:`Weight scoring and field goal efficiency. SGs are expected to convert chances. An SG with high volume but low efficiency is hurting the team.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Small forward`}),(0,o.jsx)(`span`,{children:`Balanced rating. SFs contribute across multiple categories. Look for players who contribute in at least three of: points, rebounds, assists, steals.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Power forward`}),(0,o.jsx)(`span`,{children:`Weight rebounds and interior scoring. A PF who grabs 12 boards and scores 14 on 6/9 shooting is having an excellent game even without assists or steals.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Center`}),(0,o.jsx)(`span`,{children:`Weight rebounds and blocks heavily. Centers who protect the rim and control the glass affect game outcome in ways that don't always show in traditional stats.`})]})]})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`Tracking basketball performance over a season.`}),(0,o.jsx)(`p`,{children:`Basketball seasons at youth and high school level typically run 20-30 games. That is enough data to produce meaningful trend analysis. By game ten, a player's average rating is reliable. By game twenty, you can identify consistent strengths and weaknesses clearly enough to build a targeted development plan for the off-season.`}),(0,o.jsx)(`p`,{children:`The most useful things to track over a season are: average rating, rating trend (rising, flat, or falling), consistency (how much the rating varies game to game), and how performance changes in higher-stakes games versus regular ones. Some players consistently perform better in big games â€” that is a valuable trait that raw stats alone won't reveal.`})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`FAQ.`}),(0,o.jsxs)(`div`,{className:i.grid,children:[(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Can I use this for youth basketball?`}),(0,o.jsx)(`span`,{children:`Yes. The formula works at any level. For younger players, focus on fewer stats (points, rebounds, assists, turnovers) rather than all eight inputs.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`How does Veyro compare to PER or Win Shares?`}),(0,o.jsx)(`span`,{children:`Veyro is designed for simplicity and youth/amateur use. PER and Win Shares require play-by-play data. Veyro works from a basic box score entered in under five minutes.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`What is a good rating for a high school player?`}),(0,o.jsx)(`span`,{children:`For a starter on a competitive team, 70-80 is solid. Consistently above 85 is exceptional at high school level. Below 60 consistently suggests the player may need a different role.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Should I track three-point shooting separately?`}),(0,o.jsx)(`span`,{children:`If the player takes more than four three-point attempts per game, yes. Otherwise, fold it into overall field goal efficiency. The impact is smaller at youth level than at college or pro.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`How do I handle a player who specializes in defense?`}),(0,o.jsx)(`span`,{children:`Weight steals, blocks, and plus/minus more heavily in your subjective assessment. The formula already rewards steals and blocks, but a lockdown defender who changes games without stats is genuinely hard to capture in any formula.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Can coaches use this for the whole team?`}),(0,o.jsxs)(`span`,{children:[`Yes. Use the `,(0,o.jsx)(r,{to:`/basketball`,children:`Veyro basketball calculator`}),` to rate each player after every game, then review the team view in the coach dashboard to spot who is developing fastest.`]})]})]})]})]})})}export{s as default};